-- Casino seed data: US, European, Australian, Asian casinos with GPS coordinates
-- Includes lat/lng from Google Maps Geocoding API.
-- Safe to re-run (on conflict by name does nothing).

-- Ensure lat/lng columns exist before inserting
alter table public.casinos add column if not exists lat double precision;
alter table public.casinos add column if not exists lng double precision;

-- US casinos
on conflict (lower(name)) do update set lat = excluded.lat, lng = excluded.lng;

-- European casinos
on conflict (lower(name)) do update set lat = excluded.lat, lng = excluded.lng;

-- Australian casinos
on conflict (lower(name)) do update set lat = excluded.lat, lng = excluded.lng;

-- Asian casinos
on conflict (lower(name)) do update set lat = excluded.lat, lng = excluded.lng;
